/* artifacts q04 (55 mục) — cập nhật R2 2026-06-15, bù 6 pháp bảo/đan/tài liệu có tên thật (Thiên Tổn đan, Thất Long đỉnh, Lục Đạo linh đan, Tử Tinh thạch, Yêu Huyết đan, La Lâm đan) [+xac-rua 2026-06-15T02:22:06.223Z] */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q04"]=window.__LIBQ["tien-nghich"]["q04"]||{};window.__LIBQ["tien-nghich"]["q04"]["artifacts"]={"updatedAt":"2026-06-14","count":55,"artifacts":[{"id":"thanh-van-dan","name":"Thanh Vân đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Lục phẩm thượng giai (ngụy thất phẩm — nếu mở phong ấn đúng cách đạt từ thất phẩm trở lên); tuổi ước mấy ngàn năm","soHuu":["vuong-lam"],"uuTien":80,"trangThai":"Đã dùng — Vương Lâm (phân thân) nuốt để Kết Anh @c0200","blurb":"Một trong ba loại đan nổi danh nhất của Kỳ Hoàng môn, viên đan màu xanh lấy từ đan phong/phong ấn trong đan lô cổ của Vân Phi. Do mở lệch nên bị giảm phẩm (không có dị tượng như thất phẩm thật), nhưng thực chất là lục phẩm thượng giai — công hiệu đủ giúp tu sĩ Kết Đan đột phá Nguyên Anh. Lý Mộ Uyển giám định đúng lai lịch; Vương Lâm dùng chính viên đan này, vận Cổ Thần quyết trong Nghịch Thiên châu để phân thân Kết Anh thành công, hóa giải bế tắc đột phá Nguyên Anh đeo đẳng từ @c0168/@c0185.","detail":"Đan màu xanh, kích thước thường nhưng không tỏa dị tượng khiến Lý Mộ Uyển ban đầu ngỡ là đan giả; giám định kỹ mới ra là Thanh Vân đan ngụy thất phẩm của Kỳ Hoàng môn (tứ cấp tu chân quốc). Mấy ngàn năm tuổi, vốn được phong ấn trong đan lô để giữ dược hiệu; mở phong ấn sai cách thì phẩm chất tụt một bậc. Là chìa khóa giúp Vương Lâm vượt qua điểm bế tắc Cực Cảnh để Kết Anh.","nguon":["@c0196","@c0198","@c0200"]},{"id":"doat-thien-that-dinh","name":"Đoạt Thiên Thất đỉnh","cn":"","aliases":[],"category":"than-khi","categoryLabel":"Thần khí / Bảo vật trấn tông","phamCap":"Chí bảo trấn tông Vân Thiên Tông — tích lũy linh lực cả ngàn năm","soHuu":["van-thien-tong"],"uuTien":70,"trangThai":"Của Vân Thiên Tông; bị Vương Lâm–Lý Mộ Uyển bí mật rút linh lực ngàn năm trợ Kết Anh @c0199–@c0200","blurb":"Đan đỉnh trấn tông của Vân Thiên Tông, đúc theo trí nhớ thủy tổ với hình bảy hắc long phun khói tím, đặt dưới quảng trường đại điện; không thể rời khỏi Vân Thiên Sơn. Bên trong tích lũy linh lực cả ngàn năm, dùng để tế luyện linh đan cao phẩm ('Tế đan luyện thuật'). Lý Mộ Uyển trộm linh lực giải phong ấn đan lô của Vân Phi nhân lúc đan sư Âu Dương Tử dùng đỉnh luyện đan; Vương Lâm đổi kế hoạch, dẫn linh lực ngàn năm của đỉnh xuống cho bổn tôn tu luyện thay vì phá hủy nó làm đòn sát thủ.","detail":"Lai lịch thần bí: đúc theo trí nhớ của thủy tổ Vân Thiên Tông, gắn liền với vận khí tông môn nên không rời được núi. Bảy hắc long trên đỉnh phun khói tím; vận hành cần đan sư cao cấp (Âu Dương Tử — ngũ phẩm, Nguyên Anh sơ kỳ). Linh lực ngàn năm bên trong là nguồn trợ lực then chốt cho bước dung hợp bổn tôn–phân thân để bổn tôn Kết Anh.","nguon":["@c0198","@c0199","@c0200"]},{"id":"long-tu-dinh","name":"Long tử đỉnh","cn":"","category":"linh-khi","categoryLabel":"Linh khí — Đan lô bảo vật","phamCap":"Cực phẩm (bảo vật trấn tông 8000 năm)","soHuu":["van-thien-tong"],"trangThai":"Trấn tông bảo vật Vân Thiên tông; suýt xuất hiện trong lễ thu đồ @c0189 rồi rút về","blurb":"Đan lô bảo vật linh khí tích lũy 8000 năm của Vân Thiên tông — lò luyện đan trấn tông. Trong lễ thu đồ @c0189, khi phân thân Vương Lâm dùng cấm chế thượng cổ câu đan dược thủy lam, Long tử đỉnh suýt xuất hiện rồi tự rút về; cùng dịp đó Chu Lâm xin nhận VL làm đồ đệ.","detail":"Long tử đỉnh là đan lô trấn tông của Vân Thiên tông, đã tích lũy linh khí luyện đan suốt 8000 năm @c0189. Trong lễ thu đồ ba mươi năm một lần, khi phân thân Vương Lâm dùng cấm chế thượng cổ cố ý câu loại đan dược thủy phù hợp sở trường thủy thuộc tính của Chu Lâm, Long tử đỉnh cảm ứng và suýt tự xuất hiện rồi rút về @c0189. Đây là hiện tượng cực kỳ hiếm — bảo vật cấp lò tự phản ứng với cấm chế ngoài — khiến Chu Lâm nhận ra tiềm năng phi thường của phân thân VL và chủ động xin chưởng môn nhận làm đồ đệ duy nhất @c0189.","nguon":["@c0189"]},{"id":"thanh-dong-co-kinh","name":"Thanh Đồng Cổ Kính","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo — Bắt bắt","phamCap":"Cao cấp (Nguyên Anh kỳ)","soHuu":["vuong-lam"],"trangThai":"Trong tay Vương Lâm","blurb":"Gương đồng cổ xanh — pháp bảo chuyên bắt Nguyên Anh. Phóng ánh sáng xanh trùm lên thân tu sĩ, ép Nguyên Anh không thể xuất thể; lật mặt sau có thể sao chép hình ảnh sinh vật làm mồi nhử. Vũ khí then chốt của Vương Lâm trong trận diệt Vân Thiên Tông.","detail":"Thanh Đồng Cổ Kính lần đầu xuất hiện trong trận VL tấn công Vân Thiên Tông @c0201. Công năng chính: chiếu ánh sáng xanh khóa Nguyên Anh tu sĩ không cho xuất thể — nhờ đó VL bắt sống Liễu Phỉ (Nguyên Anh trung kỳ đỉnh) và thu Nguyên Anh lão nhân áo xám (Nguyên Anh trung kỳ). Mặt sau gương có khả năng sao chép hình dạng sinh vật làm mồi nhử. VL tiếp tục dùng trong Tu Ma Hải @c0205, @c0206.","nguon":["@c0201","@c0205","@c0206"]},{"id":"tu-mac-trung","name":"Tử Mặc Trùng","cn":"","category":"linh-thu","categoryLabel":"Linh thú — Phi trùng độc","phamCap":"Độc vật xếp hạng 184 Tu Chân Giới","soHuu":["vuong-lam"],"trangThai":"Trong tay Vương Lâm (thu từ Trần Bách Lương @c0202)","blurb":"Phi trùng đen cỡ ngón tay cái; loài độc vật xếp hạng 184 trong Tu Chân Giới, da cứng, sức tấn công mạnh. VL thu được từ túi trữ vật lão tổ Trần Bách Lương (Vân Thiên Tông) sau khi giết ông trong trận đánh chiếm tông môn.","detail":"Tử Mặc Trùng là loài phi trùng độc trong danh sách xếp hạng độc vật Tu Chân Giới, vị trí 184 @c0202. Màu đen, cỡ ngón tay cái, da cứng. Trần Bách Lương từng tế bầy Tử Mặc Trùng để phá giải Cực cảnh thần thức của Vương Lâm; sau khi ông ngạnh kháng tới chết, VL lục túi trữ vật thu lấy bầy trùng, về sau dùng để chế Cấm phiên mới bằng Mặc Gian thạch.","nguon":["@c0202"]},{"id":"tam-xoa-kich-lien-mac-thanh","name":"Tam xoa kích","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo — Vũ khí","phamCap":"Nguyên Anh sơ kỳ cấp","soHuu":["vuong-lam"],"trangThai":"Trong tay Vương Lâm (thu từ đại hán Liên Mặc thành @c0206)","blurb":"Vũ khí của viên đại hán hộ pháp Nguyên Anh sơ kỳ bảo vệ lệnh bài Bí tại Liên Mặc thành. Vương Lâm thu vào túi trữ vật sau khi Văn Thú nuốt Nguyên Anh của hắn.","detail":"Tam xoa kích là pháp bảo chủ vũ của đại hán hộ pháp canh giữ lệnh bài Bí tại Liên Mặc thành @c0206. Sau khi Văn Thú của VL nuốt Nguyên Anh, VL thu toàn bộ túi trữ vật của đại hán bao gồm vũ khí này. Thông tin chi tiết về cấp bậc và công năng đặc biệt chưa được mô tả thêm trong Ch.201-210.","nguon":["@c0206"]},{"id":"vo-kiem-co-thu-hai","name":"Vỏ kiếm cổ (thứ hai)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo — Phong ấn khí","phamCap":"Bất minh (phong ấn sát khí vượt Nguyên Anh kỳ)","soHuu":["vuong-lam"],"trangThai":"Trong tay Vương Lâm — chưa rút được toàn bộ sát khí","blurb":"Vỏ kiếm cổ thứ hai VL thu được từ tu sĩ Hỏa Phần quốc. Hình dáng giống vỏ kiếm thứ nhất nhưng khác hẳn: không có hơi lạnh, ký hiệu khắc hoàn toàn khác. Phong ấn một luồng sát khí kinh thiên — VL thử rút chút xíu thì phi kiếm vỡ vụn và đất nứt mấy trăm trượng.","detail":"Vỏ kiếm cổ thứ hai xuất hiện trong chiến lợi phẩm của nhóm tu sĩ Hỏa Phần quốc mà VL đánh gặp @c0208. VL ngay lập tức nhận ra sự tương đồng với vỏ kiếm thứ nhất (từng của Bạch Triển) nhưng cũng thấy điểm khác biệt rõ rệt: không có hơi lạnh và ký hiệu khắc trên vỏ khác hoàn toàn. Khi VL thử rút một chút sát khí bên trong, phi kiếm của chính hắn vỡ vụn tức thì và mặt đất nứt ra hàng mấy trăm trượng — sát khí mạnh đến mức không thể đo lường. Vỏ kiếm thứ nhất trước đó cũng từng có sát khí mạnh nhưng không đến mức này.","nguon":["@c0208"]},{"id":"lenh-bai-bi","name":"Lệnh bài Bí","cn":"","category":"khac","categoryLabel":"Vật phẩm — Tín vật","phamCap":"Tín vật vào Bí thị","soHuu":["vuong-lam"],"trangThai":"Đã ném lại cho lão nhân Bí thị sau khi vào chợ @c0207","blurb":"Lệnh bài khắc chữ Bí màu đen — tín vật được phép tham dự Bí thị (chợ bí mật liên hội ba thành vùng nội hải Tu Ma Hải). VL đoạt từ đại hán hộ pháp Liên Mặc thành; đã dùng vào chợ một lần rồi ném lại.","detail":"Lệnh bài Bí do đại hán hộ pháp Liên Mặc thành mang theo để vào Bí thị @c0206. VL đoạt được sau khi Văn Thú nuốt Nguyên Anh hắn. Dùng lần đầu và duy nhất để vào Bí thị @c0207. Sau khi giao dịch xong, VL ném lại lệnh bài cho lão nhân phụ trách Bí thị vì không cần nữa.","nguon":["@c0206","@c0207"]},{"id":"mu-rom-che-mat","name":"Mũ rơm (che diện mạo)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["vuong-lam"],"trangThai":"Đang giữ","blurb":"Mũ rơm pháp bảo tích hợp trận pháp tinh diệu che giấu diện mạo người đội; khi thần thức địch quét qua sẽ bị phản kích tức thì. VL nhận trước khi xâm nhập Bạch Vân Tông.","detail":"Lão nhân Anh Biến kỳ chuẩn bị mũ rơm cho VL trước khi vào Bạch Vân Tông @c0235. Trận pháp bên trong đủ tinh diệu để che giấu diện mạo trước mắt Hóa Thần tu sĩ; cơ chế phản kích thần thức bảo vệ danh tính người đội. Cuối chương @c0236 VL tháo mũ ra sau khi rời Bạch Vân Tông.","nguon":["@c0235","@c0236"]},{"id":"doa-hoa-den","name":"Đóa hoa đen","cn":"","category":"linh-vat","categoryLabel":"Linh vật — Tài liệu luyện đan","phamCap":"Tài liệu quý bậc nhất","soHuu":["vuong-lam"],"trangThai":"Đã dùng @c0240","blurb":"Đóa hoa màu đen — tài liệu quý bậc nhất để luyện chế linh đan; công năng đặc biệt là ngưng tụ hồn phách người phàm mới chết, giúp hồn lực mạnh hơn khi nhập biển luân hồi để đầu thai vào chỗ tốt hơn. Không phải vật phàm tục.","detail":"Vương Lâm dùng đóa hoa đen khi cha Đại Ngưu vừa qua đời @c0240. Hóa tan đóa hoa thành điểm sáng, nhập vào hồn phách người chết; hồn phách từ lạnh lẽo sắp tiêu tán trở nên ấm áp và hồn lực mạnh hơn — đủ để chọn nơi đầu thai tốt. VL nhắc rõ đây là tài liệu quý nhất dùng luyện đan nhưng hắn dùng cho mục đích trợ giúp người chết thay vì luyện đan.","nguon":["@c0240"]},{"id":"to-linh-bai-gia","name":"Tổ linh bài (giả)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo — Tín vật giả mạo","phamCap":"Không rõ","soHuu":["lao-nhan-anh-bien"],"trangThai":"Đã trả lại Bạch Vân Tông @c0236","blurb":"Tổ linh bài màu đen phát ánh sáng bảy màu — tín vật tổ tiên của Bạch Vân Tông, ai giữ thì tông môn phải tuân lệnh. Lão nhân Anh Biến kỳ dùng nó ép 3 Hóa Thần thi triển ý cảnh; thực ra là đồ giả do chính lão tự chế, bản thân Bạch Vân Tông không phát hiện ra.","detail":"Lão nhân dùng Tổ linh bài ép Bạch Vân Tông phục tùng @c0236; sau đó trả lại tông môn. Tới @c0237 lão nhân thừa nhận với VL đây là đồ giả do chính lão làm — ám chỉ lão có kỹ thuật chế tác/giả mạo cực cao. Bạch Vân Tông xuyên suốt không nhận ra sự giả mạo.","nguon":["@c0236","@c0237"]},{"id":"tinh-do-thien-van","name":"Tinh đồ Thiên Vận Tinh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo — bản đồ","phamCap":"Vô cấp (lưu trực tiếp vào đầu VL)","soHuu":["vuong-lam"],"trangThai":"Đang giữ @c0241","blurb":"Bản đồ sao trời Thiên Vận Tử lưu lại trong đầu Vương Lâm; chứa vị trí Thiên Vận Tinh (tinh cầu của Thiên Vận Tử, lớn hơn Chu Tước tinh vô số lần).","detail":"Thiên Vận Tử lưu tinh đồ này vào đầu VL khi thu hắn làm ký danh đệ tử @c0241. VL hiện tại không có khả năng đến Thiên Vận Tinh — chỉ là mục tiêu dài hạn sau khi đạt đủ tu vi vũ trụ.","nguon":["@c0241"]},{"id":"but-long-den-hac-hon","name":"Bút lông đen (Hắc Hồn Phái)","cn":"","category":"bao-boi-tran-phai","categoryLabel":"Bảo bối trấn phái","phamCap":"Cực cao (khiến trời đất biến sắc, cả hai lão già phái khác hoảng sợ)","soHuu":[],"trangThai":"Đang dùng trong chiến tranh @c0250","blurb":"Bảo bối trấn phái mạnh nhất của Hắc Hồn Phái — chiếc bút lông đen ngưng tụ từ vô số luồng khí đen. Khi xuất hiện, trời đất biến sắc; cả hai lão già Thủy Mặc Môn và Bạch Vân Tông đều hoảng sợ.","detail":"Nam tử trẻ nhu nhược của Hắc Hồn Phái vung tay gọi bút lông đen trong đại chiến Tuyết Vực @c0250. Sắc mặt tái nhợt trước khi gọi nhưng hồng hào khi cầm bút — gợi ý tiêu hao sinh lực khi dùng. Đây là bảo bối mạnh nhất trong bốn phái; vai trò cụ thể trong trận chiến chưa được triển khai.","nguon":["@c0250"]},{"id":"cuc-quang-hoa-tuyen","name":"Cực Quang Hỏa Tuyến","cn":"","aliases":[],"category":"thien-tai-dia-bao","categoryLabel":"Thiên tài địa bảo","phamCap":"Cao (giúp linh thú đột phá trung phẩm linh cấp)","soHuu":["van-thu"],"trangThai":"Đã dùng — Văn thú hấp thu","blurb":"Sợi kim tuyến sắc vàng ánh lửa — loài thiên tài địa bảo cực hiếm trên Tu Ma hải. Linh thú dung hợp sẽ bùng phát uy năng lớn; Văn thú hấp thu 1 sợi từ Tôn Điên cùng hơn 10 sợi tự tìm kiếm → đột phá trung phẩm linh cấp, thân dài ~30 trượng.","detail":"Tôn Điên tặng cho Vương Lâm 1 sợi Cực Quang Hỏa Tuyến khi gặp trên Tu Ma hải @c0265. Văn thú dung hợp tổng cộng hơn 10 sợi (tự hấp thu thêm ngoài 1 sợi Tôn Điên tặng) → đột phá từ hạ phẩm lên trung phẩm linh cấp, thân to ~30 trượng @c0266.","nguon":["@c0265","@c0266"]},{"id":"ngoc-dinh-vi-hoi","name":"Ngọc đỉnh Vi Hồi","cn":"","aliases":[],"category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Tiên giới (nguồn gốc không rõ)","soHuu":["vuong-lam"],"trangThai":"Đang giữ","blurb":"Vật phẩm tự xuất hiện khi Vương Lâm bước vào cánh cửa tiên giới, lớn cỡ ba bàn tay. Dùng để rời tiên giới: tế khởi bằng tâm niệm ở khu vực đặc biệt, mất khoảng thời gian đốt một nén hương, đưa người trở lại tu chân Tinh tương ứng.","detail":"Xuất hiện tự động khi Vương Lâm tiến vào cánh cửa tiên giới @c0270. Cơ chế: kích hoạt bằng tâm niệm, chỉ dùng được ở 'khu vực đặc biệt' (chưa rõ điều kiện cụ thể), mất khoảng thời gian đốt một nén hương để hoàn thành dịch chuyển, trả người về tu chân Tinh tương ứng (Chu Tước Tinh với VL).","nguon":["@c0270"]},{"id":"xa-than-xa","name":"Xạ Thần xa","cn":"","aliases":["chiến xa Thiên Bảo"],"category":"linh-khi","categoryLabel":"Linh khí chiến đấu","phamCap":"Tiên nhân luyện chế (trước đại nạn)","soHuu":["vuong-lam"],"uuTien":null,"trangThai":"Đang giữ — phong ấn thú hồn, thu nhỏ trong túi trữ vật","blurb":"Ba chiếc chiến xa khổng lồ (~10 trượng) do Thiên Bảo thượng nhân luyện chế. Dùng thú hồn dẫn phát; thu nhỏ được khi không dùng. Vương Lâm thu trọn ba chiếc trong động phủ Thiên Bảo.","detail":"Thiên Bảo thượng nhân — tiên nhân chuyên luyện chế pháp bảo trước đại nạn tiên giới — để lại ba Xạ Thần xa trong gian bí mật của động phủ. VL dùng quang quyển đen thu chiếc giữa @c0282, rồi thu nốt hai chiếc còn lại @c0283. Cơ chế hoạt động: thú hồn làm nguồn lực dẫn phát; kích thước thật ~10 trượng nhưng có thể thu nhỏ để vận chuyển. Chức năng tấn công chi tiết chưa được VL kiểm chứng.","nguon":["@c0281","@c0282","@c0283"]},{"id":"tinh-la-ban","name":"Tinh La Bàn (Ngụy)","cn":"","aliases":["Ngụy Tinh La Bàn","la bàn Cự Ma tộc"],"category":"phap-bao","categoryLabel":"Pháp bảo định hướng","phamCap":"Ngụy chế — bản sao chưa đạt nguyên bản","soHuu":["sat-ho"],"uuTien":null,"trangThai":"Hư hỏng — không dùng được sau trận trong hư vô @c0287","blurb":"Bản sao chép chí bảo Tinh La Bàn của Cự Ma tộc — dùng để định hướng và di chuyển trong hư vô Tiên Giới Toái Phiến. Cần 5 người ngồi đúng vị trí mới kích hoạt được. Bị hư hỏng sau khi gặp sinh vật Hư tại tầng 1.","detail":"Tinh La Bàn chính hãng là chí bảo của Cự Ma tộc; Sất Hổ chỉ có bản ngụy (sao chép). Cơ chế: 5 người ngồi đúng vị trí (bắc/nam/đông/tây/trung), la bàn tạo ra sàn hư vô cho di chuyển trong không gian mảnh vỡ tiên giới. Trong hư vô tầng 1 gặp sinh vật Hư — chúng tấn công hút linh lực, phá hỏng la bàn sau trận chiến @c0287. Theo ký ức Đồ Ti mà VL có được: Kim tử thạch là nguyên liệu để phục chế Tinh La Bàn chính hãng — VL thu Kim tử thạch với mục đích này.","nguon":["@c0286","@c0287"]},{"id":"xa-than-xa-tien-di","name":"Xạ Thần Xa (Tiên Di Chi Địa)","cn":"","aliases":["Chiến Xa cổ Tiên Di"],"category":"phap-bao","categoryLabel":"Pháp bảo chiến đấu","phamCap":"Cổ vật Tiên Di tộc","soHuu":["vuong-lam"],"uuTien":null,"trangThai":"Đang giữ — thu vào Khu Thú Quyển","blurb":"Chiến xa cổ Tiên Di Chi Địa có Hồn Thú ngụ bên trong. Uy lực kinh hoàng — Hồn Thú xuyên qua cơ thể địch và nuốt tàn hồn. Chi phí: 1 cực phẩm linh thạch/lần dùng. VL thu vào Khu Thú Quyển, đặt tên Xạ Thần Xa.","detail":"Thu được trong Tiên Di Chi Địa @c0317. Hồn Thú ngụ bên trong — khi kích hoạt, hấp thu hắc mang từ mũi nhọn chiến xa, thân thể trở nên khổng lồ; vọt tới bằng tốc độ cực nhanh xuyên qua cơ thể địch và cắn chặt nuốt tàn hồn. Địch bị nứt từ mi tâm hóa tro bụi. Sau khi dùng, Hồn Thú hung tính cắn trả — phải đánh ấn quyết lên chiến xa để xích sắt hư ảo trói Hồn Thú kéo về. Chi phí: 1 khối cực phẩm linh thạch/lần dùng. VL dùng lần đầu giết Xỉ Mộc (lục diệp Chiến Thú Sĩ) @c0324. Cảnh báo: dùng nhiều sẽ bị hút thành xương khô.","nguon":["@c0317","@c0324"]},{"id":"luc-pham-quy-nguyen-dan","name":"Lục phẩm Quy Nguyên đan","cn":"","aliases":["linh đan lục phẩm","phương thuốc lục phẩm"],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Lục phẩm","soHuu":["vuong-lam"],"uuTien":null,"trangThai":"Đã dùng — Lý Mộ Uyển uống @c0312; phương thuốc (bản gốc) VL lấy từ Chu Ngạn Hoành @c0311","blurb":"Đan dược lục phẩm do Âu Dương Tử luyện chế 6+ năm theo phương thuốc VL thu được. Tăng tốc hấp thu linh lực trời đất, giúp kết anh — nhưng nếu thân thể quá yếu sẽ bị kết tinh. Lý Mộ Uyển dùng và chết.","detail":"Phương thuốc lục phẩm ban đầu bị Chu Ngạn Hoành đoạt tại đấu giá Luyện Khí Các @c0310. VL lấy lại @c0311. Âu Dương Tử luyện thành đan lục phẩm Quy Nguyên đan @c0312. LMU uống vào linh lực điên cuồng tụ nhưng thân xác quá yếu → kết tinh thành tinh thạch → nguyên anh thoát xác @c0312–@c0313. Mỗi trăm năm chỉ được dùng 1 viên với người thể chất bình thường.","nguon":["@c0311","@c0312","@c0313"]},{"id":"luan-hoi-thu","name":"Luân Hồi Thụ (Luân Hồi Mộc)","cn":"","aliases":["Luân Hồi Mộc","cây Luân Hồi"],"category":"linh-vat","categoryLabel":"Linh vật thiên nhiên","phamCap":"Cổ thực vật Tiên Di Chi Địa","soHuu":["vuong-lam"],"uuTien":null,"trangThai":"Đã dùng — VL chế tác tượng gỗ Tuế Nguyệt từ đoạn gỗ Luân Hồi Mộc @c0330","blurb":"Cây cổ khô héo ngàn năm sâu trong tầng 3 Tiên Di Chi Địa. Cho quả Luân Hồi (tăng 30%+ xác suất bước vào Anh Biến). VL sở hữu toàn bộ cây sau khi thôi hóa đủ 3 quả. Gỗ cây sau đó được dùng chế tác tượng Tuế Nguyệt.","detail":"Nằm sâu trong tầng 3 Tiên Di Chi Địa — đây là lý do nhóm Hồ lão xâm nhập. Cây già cỗi khô héo, ngàn năm tuổi. Quả Luân Hồi phát sáng vàng chói, chất lỏng sền sệt màu vàng. Để thôi hóa (ép cây cho quả), cần hai nhân tố: hy sinh tuổi thọ của người (cứ 1 giáp = 12 năm thì cây già thêm 1 năm, hy sinh đủ → cho quả). Hồ lão hy sinh tuổi thọ Hứa La + Vận Manh để lấy 2 quả; VL lấy 1 quả từ đó + sở hữu cả cây @c0322–@c0323. VL chặt cây thành từng đoạn nhỏ bỏ vào túi trữ vật (nguyên cây không bỏ vào được) @c0324. Sau khi ra ngoài, VL dùng 1 quả cho Bản Tôn (chính thức trở thành Cổ Thần) @c0330, rồi dùng đoạn Luân Hồi Mộc chế tác tượng gỗ Tuế Nguyệt @c0330.","nguon":["@c0319","@c0322","@c0323","@c0324","@c0330"]},{"id":"luan-hoi-qua","name":"Quả Luân Hồi","cn":"","aliases":["Luân Hồi Quả"],"category":"linh-vat","categoryLabel":"Linh vật thiên nhiên","phamCap":"Quả của Luân Hồi Thụ — cổ thực vật Tiên Di Chi Địa","soHuu":["vuong-lam"],"uuTien":null,"trangThai":"Đã dùng hết — VL giữ 1 quả (Hồ lão lấy 2 quả); 1 quả VL dùng cho Bản Tôn @c0330","blurb":"Quả của Luân Hồi Thụ — phát ánh sáng vàng chói. Khi dùng: chất lỏng sền sệt vàng ngấm vào da thịt, lan khắp toàn thân tạo tấm lưới vàng, hấp thu vào máu thịt — tăng vô số lần tốc độ hấp thu linh lực thiên địa, tăng 30%+ xác suất đột phá Anh Biến. Bản Tôn dùng 1 quả → chính thức trở thành bộ tộc Cổ Thần.","detail":"Tổng cộng 3 quả thôi hóa được trong trận chiến tầng 3 Tiên Di Chi Địa. Hồ lão lấy 2 quả @c0323; VL lấy 1 quả. VL để dành cho Bản Tôn (vì Bản Tôn là thể Cổ Thần — dùng quả thích hợp hơn VL dùng cho tu vi bình thường). Bản Tôn bóp vỡ quả @c0330: chất lỏng vàng ngấm vào vết rạn trên da → lan khắp toàn thân thành tấm lưới vàng → kim quang dung nhập máu thịt → tất cả kinh mạch bị hấp thu/thay đổi → tốc độ hấp thu linh lực thiên địa tăng vô số lần → chính thức trở thành bộ tộc Cổ Thần.","nguon":["@c0319","@c0322","@c0323","@c0330"]},{"id":"chuong-linh-dang-bo-3","name":"Chuông Linh Đang (bộ 3 chiếc)","cn":"","aliases":["Linh Đang"],"category":"phap-bao","categoryLabel":"Pháp bảo — Thượng cổ","phamCap":"Thượng cổ — 3 chuông cảm ứng với nhau bất kể khoảng cách","soHuu":["vuong-lam"],"uuTien":85,"trangThai":"VL sở hữu 3 chiếc — đã vỡ 2 chiếc để luyện Âm Ba Linh Giáp @c0332; còn 1 chiếc và tặng 1 chiếc cho Chu Như @c0331","blurb":"Bộ 3 chuông thượng cổ — cả 3 cảm ứng với nhau dù ở bất cứ đâu: ai cầm chuông này đánh sẽ cảm ứng với người cầm chuông kia. VL sở hữu từ trước c0331; tặng 1 cho Chu Như để liên lạc khẩn cấp. 2 chiếc bị đập vỡ để luyện Âm Ba Linh Giáp trong trận Liêu Phàm @c0332.","detail":"3 chuông thượng cổ — cơ chế: ai cầm chuông đánh, người cầm chuông kia nghe thấy dù ở bất cứ đâu (không bị giới hạn không gian). VL giữ 2, tặng Chu Như 1 để gọi cứu khi nguy hiểm @c0331. Trong trận chiến Liêu Phàm @c0332, VL đập vỡ 2 chuông (giữ lại 1 trong tay Chu Như), dùng âm ba ngưng tụ thành Âm Ba Linh Giáp — khải giáp phòng thủ cực mạnh.","nguon":["@c0331","@c0332"]},{"id":"bang-than-ban-menh","name":"Băng Thần (trọng bảo Tuyết Vực quốc)","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo — Trọng bảo quốc gia","phamCap":"Trọng bảo Tuyết Vực quốc — 500 năm chế tác","soHuu":["hong-diep"],"uuTien":90,"trangThai":"Đang theo chủ nhân — Hồng Điệp vẫn sống @c0340 (dù bị hạ thủ)","blurb":"Trọng bảo Tuyết Vực quốc, 500 năm chế tác — hóa thân người băng tuyết khổng lồ cao mười trượng, khi Hồng Điệp nhập vào bên trong thì điều khiển trực tiếp. Pháp bảo trứ danh tại Chu Tước quốc.","detail":"Băng Thần là trọng bảo Tuyết Vực quốc (500 năm chế tác), Hồng Điệp dùng trong trận đấu VL — hóa thành người băng tuyết khổng lồ cao hàng chục trượng @c0335–@c0340. Khi Hồng Điệp nhập toàn thân vào trong, người khổng lồ tự chuyển động do Hồng Điệp điều khiển từ bên trong @c0338. Bên trong chứa Côn Cực Tiên. Bị chặt đứt cánh tay phải bởi tiên kiếm VL @c0338; thu nhỏ dần sau các đòn tiên kiếm và Hồn Thú @c0338–@c0339; cuối cùng tam linh sắp nổ khi Công Tôn Phá can thiệp @c0340.","nguon":["@c0335","@c0336","@c0337","@c0338","@c0339","@c0340"]},{"id":"con-cuc-tien","name":"Côn Cực Tiên","cn":"","aliases":["Nhuyễn tiên","Roi mềm trọng bảo"],"category":"phap-bao","categoryLabel":"Pháp bảo — Trọng bảo","phamCap":"Trọng bảo — Thiên Ngọc tông; rút nguyên thần bất kỳ ai ở gần","soHuu":["hong-diep"],"uuTien":92,"trangThai":"Bị Công Tôn Phá thu lại sau trận @c0340","blurb":"Trọng bảo nhuyễn tiên (roi mềm) của Thiên Ngọc tông — ẩn trong cơ thể người băng tuyết khổng lồ (Băng Thần). Khả năng cực kỳ nguy hiểm: (1) rút nguyên thần bất kỳ ai ở gần; (2) tốc độ phóng ra nhanh hơn tia chớp 3 lần; (3) mỗi lần lóe làm yếu sợi tơ Thiên Kiếp. VL đánh giá: thắng cũng như thua nếu bị Côn Cực Tiên rút nguyên thần.","detail":"Côn Cực Tiên ẩn trong ngực người khổng lồ Băng Thần @c0337. Cơ chế: ai ở gần sẽ bị rút nguyên thần, thân thể bị hủy diệt. Đánh trúng VL @c0337 — nguyên thần VL bị rút ra ngoài thân thể bay ra trăm trượng; VL bấm quyết chui lại vào thân. Phóng lần 2 tốc độ nhanh hơn tia chớp 3 lần — VL dùng na di tránh trăm dặm vẫn bị chạm nhẹ @c0337. Hứa Lập Quốc dùng hắc khí tiên kiếm cản 1 đòn Côn Cực Tiên nhân bản khi người khổng lồ vung nhuyễn tiên xuống thân VL @c0338. Công Tôn Phá thu lại sau khi trận kết thúc @c0340.","nguon":["@c0337","@c0338","@c0340"]},{"id":"vu-phien-du-bao","name":"Vũ phiến Dư bảo","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo — Vũ khí quạt","phamCap":"Chưa rõ cụ thể","soHuu":[],"uuTien":null,"trangThai":"Bị tranh chấp — Liêu Phàm đến đòi VL, VL từ chối; thực ra Liêu Phàm đến với mục đích dò xét thực lực","blurb":"Pháp bảo dạng quạt — Liêu Phàm đến Tằng Ngưu lấy danh nghĩa đòi Vũ phiến Dư bảo này để thăm dò thực lực VL. Không rõ ai là chủ nhân hợp lệ hay chi tiết pháp bảo; đây chỉ là cái cớ Liêu Phàm dùng.","detail":"Liêu Phàm đến sơn cốc Tằng Ngưu xưng muốn lấy lại Vũ phiến Dư bảo @c0331. VL từ chối. Nhưng mục đích thật của Liêu Phàm là vâng lệnh tông chủ Băng Tuyết Thần Điện dò xét thực lực VL bằng Đồng Chung — Vũ phiến chỉ là cái cớ @c0331. Chi tiết thực chất của pháp bảo này không được nguyên tác triển khai thêm.","nguon":["@c0331"]},{"id":"khon-tinh-nham","name":"Khôn Tinh Nham","cn":"","aliases":["linh thạch đỏ hấp thu linh lực"],"category":"linh-vat","categoryLabel":"Linh vật — Linh thạch đặc biệt","phamCap":"Nguyên liệu đặc biệt (lõi ngụy linh nhãn)","soHuu":["vuong-lam"],"trangThai":"VL thu lấy khi ngụy linh nhãn bị phá @c0351","blurb":"Linh thạch đỏ đặc biệt có khả năng hấp thu linh lực — là lõi cốt của ngụy linh nhãn mà Luyện Hồn Tông dùng để trấn áp linh mạch ngoại vi. VL phát hiện và thu lấy sau khi phá ngụy linh nhãn, chuẩn bị hấp thu cạn linh mạch @c0351.","detail":"Khôn Tinh Nham là loại linh thạch đỏ có tính năng đặc biệt: hấp thu và chứa trữ linh lực. Luyện Hồn Tông dùng làm lõi cốt của ngụy linh nhãn đặt tại linh mạch ngoại vi để trấn áp/kiểm soát linh mạch. Khi VL phá ngụy linh nhãn, linh thạch lộ ra và VL thu lấy (@c0351). Ứng dụng tiềm năng: nguyên liệu hoặc công cụ liên quan hấp thu linh lực.","nguon":["@c0351"]},{"id":"hon-phien-mot-kim-tuyen","name":"Hồn Phiên một kim tuyến","cn":"","aliases":["cờ tím một kim tuyến"],"category":"phap-bao","categoryLabel":"Pháp bảo — Hồn Phiên","phamCap":"Nhất kim tuyến (cấp thấp nhất có kim tuyến)","soHuu":["vuong-lam"],"trangThai":"VL cướp từ tu sĩ Kết Đan hậu kỳ trung niên, đã dung nhập thần thức @c0357","blurb":"Cờ nhỏ màu tím có một đạo kim tuyến — hồn phách bên trong phát hắc khí không bị gió thổi tiêu tan, có thể trưởng thành (thần thông tiếp tục tăng khi bị giam). Mấy trăm hồn phách, một số uy áp ngang Kết Đan kỳ. VL cướp từ tu sĩ trung niên tại nội môn Luyện Hồn Phong @c0357.","detail":"Đặc điểm nổi bật: hồn phách phát hắc khí — khác hồn phách tầm thường (có thể bị gió thổi tiêu tan), không tan dù bị tấn công. Hồn phách trong Hồn Phiên có thể 'trưởng thành' — thần thông tiếp tục lớn mạnh khi bị giam giữ, không suy yếu đi. Mấy trăm hồn phách, một số phát uy áp ngang tu sĩ Kết Đan kỳ bình thường. VL dùng trảo cách không đoạt từ tay tu sĩ trung niên, điểm lau sạch thần thức đối phương, dung nhập thần thức của mình — cảm giác 'nước mát thấm vào', hồn phách bị hút hết vào (@c0357).","nguon":["@c0357"]},{"id":"kim-sac-hon-phien","name":"Kim Sắc Hồn Phiên (Kim Sắc Tiểu Kỳ)","cn":"","aliases":["Kim sắc tiểu kỳ","Kim sắc Hồn Kỳ"],"category":"phap-bao","categoryLabel":"Pháp bảo — Hồn Phiên trấn phái","phamCap":"Trấn phái chi bảo (Luyện Hồn Tông)","soHuu":[],"trangThai":"Còn bên trong linh mạch Luyện Hồn Phong, bị thượng cổ hồn cấm bảo vệ; chủ hồn thật sự (Kỳ Lân kim mang) vừa xuất hiện đối mặt VL @c0360","blurb":"Pháp bảo trấn phái Luyện Hồn Tông — cờ nhỏ màu vàng kim nằm sâu trong linh mạch, bị thượng cổ hồn cấm bảo vệ từ bên ngoài. Bên trong chứa chủ hồn thật sự (hình Kỳ Lân kim mang) + nhiều phó hồn. Thuỷ tổ Luyện Hồn Tông để lệnh 'dành cho người có đức'. Ngô Đạo Khải 3 lần thách đấu đều không lấy được @c0358-@c0360.","detail":"Cấu trúc: kim sắc tiểu kỳ (cờ nhỏ vàng kim) là ngoại hình, bên trong chứa: (1) nhiều phó hồn hình Kỳ Lân yêu thú canh giữ bên ngoài; (2) chủ hồn thật sự bên trong (khí tức màu vàng, cực cường đại — khi xuất hiện hấp thu toàn bộ hồn phách phó hồn, ngưng tụ thành Kỳ Lân khổng lồ toàn thân kim mang, không còn cảm giác hồn phách mà như thật thể). Màn sương đen tràn ra từ trong tiểu kỳ, hồn cấm thượng cổ bảo vệ bên ngoài hấp thu linh lực từ linh mạch để nuôi dưỡng. Thuỷ tổ tông để lệnh dành cho 'người có đức' — không ai được giành. VL với tu vi Nguyên Anh trung kỳ trước đó không đối phó nổi; sau khi đột phá lại Nguyên Anh (thực chất Hóa Thần không ý cảnh) mới đủ sức đập phó hồn nhưng chủ hồn lập tức xuất hiện thách đấu (@c0358-@c0360).","nguon":["@c0358","@c0359","@c0360"]},{"id":"hon-phien-hai-kim-tuyen","name":"Hồn Phiên hai kim tuyến (Thiên Hồn Phiên — Quách Đông Kiện)","cn":"","aliases":["Thiên Hồn Phiên Quách Đông Kiện"],"category":"phap-bao","categoryLabel":"Pháp bảo — Hồn Phiên","phamCap":"Nhị kim tuyến (Thiên Hồn Phiên cấp)","soHuu":["vuong-lam"],"trangThai":"VL thu lấy sau khi Quách Đông Kiện quy phục @c0359","blurb":"Hồn Phiên hai kim tuyến của Quách Đông Kiện — rung lên phóng ra hồn phách đa cấp: Trúc Cơ, Kết Đan và một hồn phách Nguyên Anh kỳ hai sừng (cực hiếm). Đây là Thiên Hồn Phiên (từ nhị kim tuyến trở lên có thần thông). VL thu lấy sau khi thi triển Hồn Tuyền khiến Quách Đông Kiện quy phục @c0358-@c0359.","detail":"Hai đạo kim tuyến = phân cấp Thiên Hồn Phiên. Khi rung phóng ra hồn phách: hóa thành hắc khí hồn mang + gương mặt dữ tợn, chứa hồn phách đa cấp từ Trúc Cơ → Kết Đan → một hồn phách Nguyên Anh kỳ rất lớn (hai sừng trên đầu, tản mát khí tức Nguyên Anh). Hồn phách Nguyên Anh hai sừng: đổi được từ Tô Kim Thế ở Trừu Phách phong (đổi bằng Bách Hồn Phiên 900 hồn phách). Sau khi VL thi triển Hồn Tuyền hút sạch hồn phách và Quách Đông Kiện quy phục, VL thu lấy Hồn Phiên (@c0358-@c0359).","nguon":["@c0358","@c0359"]},{"id":"van-hon-phien-ngo-dao-khai","name":"Vạn Hồn Phiên (Ngô Đạo Khải)","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo — Hồn Phiên","phamCap":"Vạn Hồn Phiên cấp (màu vàng nhạt)","soHuu":["vuong-lam"],"trangThai":"VL thu lấy khi Ngô Đạo Khải bị điểm hôn mê @c0360","blurb":"Vạn Hồn Phiên màu vàng nhạt của Ngô Đạo Khải, đại trưởng lão Luyện Hồn Phong. Chủ hồn: tu sĩ Nguyên Anh hậu kỳ. Phó hồn: 10 tu sĩ Nguyên Anh trung/sơ kỳ. Còn lại vô số hồn phách. Dùng chiêu Vạn hồn phệ + Huyết tế trong chiến đấu. VL thu lấy khi Ngô Đạo Khải hôn mê @c0360.","detail":"Vạn Hồn Phiên = cấp cao nhất Hồn Phiên (vạn hồn phách). Màu vàng nhạt. Cấu trúc của pháp bảo Ngô Đạo Khải: chủ hồn là một tu sĩ Nguyên Anh hậu kỳ + 10 phó hồn Nguyên Anh trung/sơ kỳ + vô số hồn phách cấp thấp. Ngô Đạo Khải dùng chiêu 'Vạn hồn phệ' (phất Hồn Phiên, triệu toàn bộ hồn phách xông vào) kết hợp 'Huyết tế' (quả huyết cầu kích nội công ngoại kích) để chiến đấu Kỳ Lân phó hồn. VL điểm Ngô Đạo Khải hôn mê và thu lấy (@c0360).","nguon":["@c0360"]},{"id":"than-phien-linh-tu-moc","name":"Thần Phiên Linh (Tử Mộc Phiên Linh)","cn":"","aliases":["Tử Mộc Phiên Linh","chuông gỗ Toả Thần phong"],"category":"phap-bao","categoryLabel":"Pháp bảo — Trọng bảo","phamCap":"Trọng bảo Toả Thần phong (Luyện Hồn Tông)","soHuu":["vuong-lam"],"trangThai":"VL thu lấy từ Ngô Đạo Khải khi lão hôn mê @c0360","blurb":"Trọng bảo của Toả Thần phong — một trong tam phong Luyện Hồn Tông. Hình dạng: cái chuông lớn, nắm bằng gỗ có vân gỗ thiên nhiên phức tạp. Khi rung phát tiếng 'đinh đinh đang đang' → hóa thành yêu thú hư ảo hình người, gào rít tấn công mục tiêu. Ngô Đạo Khải mượn từ Toả Thần phong để chiến đấu Kim sắc Hồn Phiên; VL thu lấy sau khi Ngô Đạo Khải hôn mê @c0360.","detail":"Tên gọi: Thần Phiên Linh = Tử Mộc Phiên Linh (hai tên cho cùng một bảo vật). Đặc điểm: nắm bằng gỗ có vân gỗ thiên nhiên phức tạp (khác pháp bảo thông thường). Khi rung: phát tiếng đinh đinh đang đang → sinh ra các yêu thú hư ảo hình người gào rít, tấn công và kiềm chế mục tiêu. Ngô Đạo Khải dùng để kiềm chế 2 Kỳ Lân phó hồn của Kim sắc Hồn Phiên khi con thứ 3 xuất hiện. Là trọng bảo — loại pháp bảo cao cấp thuộc về cả phong, không phải cá nhân. Ngô Đạo Khải phải mượn từ Toả Thần phong để dùng. VL thu lấy khi Ngô Đạo Khải hôn mê (@c0360).","nguon":["@c0360"]},{"id":"hon-phach-anh-bien-ky-ly-nguyen-phong","name":"Hồn phách Anh Biến kỳ (Lý Nguyên Phong)","cn":"","aliases":["hồn phách vàng Lý Nguyên Phong"],"category":"phap-bao","categoryLabel":"Pháp bảo — Hồn phách","phamCap":"Hồn phách Anh Biến kỳ (tối cao)","soHuu":["vuong-lam"],"trangThai":"VL phong ấn trong túi trữ vật sau khi Trừu Phách Lý Nguyên Phong @c0368","blurb":"Hồn phách Anh Biến kỳ của Lý Nguyên Phong — rút ra bằng thuật Dẫn Hồn (nhánh Trừu Phách) sau khi lão đầu hàng. Hiện thành luồng ánh sáng màu vàng, thân thể Lý Nguyên Phong nhanh chóng khô héo chỉ còn da bọc xương. Phong ấn trong túi trữ vật VL, có thể dùng cho các mục đích tu luyện hoặc luyện hồn phiên sau này.","detail":"Thu được qua thuật Dẫn Hồn: VL điểm ngón tay vào khoảng không, đạo linh quang bay vào mi tâm Lý Nguyên Phong — rút hồn phách Anh Biến kỳ ra ngoài. Hồn phách hiện thành luồng ánh sáng màu vàng đặc trưng của tu sĩ Anh Biến. Thân thể Lý Nguyên Phong khô héo (chỉ còn da bọc xương) sau khi bị rút hồn — 'một đời kiêu hùng cứ thế mà bỏ mình'. Điều kiện: Lý Nguyên Phong trước đó đã đầu hàng VL (bỏ ý định tự bạo để không hủy diệt Tuyết Vực quốc). VL phong ấn cho vào túi trữ vật — tiềm năng dùng cho Thập Ức Tôn Hồn Phiên hoặc mục đích tu luyện sau này (@c0368).","nguon":["@c0368"]},{"id":"thap-uc-ton-hon-phien-ban-sao","name":"Thập Ức Tôn Hồn Phiên (bản sao — VL dùng)","cn":"","aliases":["bản sao Thập Ức Tôn Hồn Phiên","hồn phiên vàng tím","Tôn Hồn Phiên"],"category":"phap-bao","categoryLabel":"Pháp bảo — Chí bảo Luyện Hồn Tông","phamCap":"Ngụy tiên bảo (dùng cả linh lực lẫn tiên lực) — chí bảo bậc nhất Chu Tước tinh; bản sao 1/3 uy lực chủ phiên","soHuu":["vuong-lam"],"trangThai":"Bản sao hoàn thành tế luyện @c0370; đã dùng lần đầu @c0374 (thôn phệ Cự Ma lão tổ), lần hai @c0390 (dung hợp chủ hồn, khiến cửu diệp thuật chú sư lui binh); chỉ dùng 2 lần rồi tan biến. Chủ phiên chính thức sẽ trao toàn quyền cho VL sau hai năm @c0387","blurb":"Bản sao (phân thân) Thập Ức Tôn Hồn Phiên — chí bảo số một Luyện Hồn Tông, ngang hàng thần xa và Vũ Chi Kiếm Tiên trên toàn Chu Tước tinh. Được phân loại ngụy tiên bảo — dùng cả linh lực lẫn tiên lực, khiến ngay cả Vấn Đỉnh lão quái cũng kiêng kị. Thần thông gốc = dung hợp hồn phách; vũ khí thật sự đáng sợ là đệ tứ chủ hồn (mấy vạn năm chỉ xuất một lần).","detail":"Chủ phiên chính thức: đang ở bên Độn Thiên bế quan trong vòng tròn đỏ như máu tại Luyện Hồn tông; Độn Thiên hứa sau hai năm trao toàn quyền cho VL @c0387. Bản sao: 1/3 uy lực chủ phiên, dùng tối đa 2 lần rồi tan biến. Cấu trúc: bên trong là hồn hải chứa vô số hồn phách; cốt lõi là 12 hồn phách tử kim (Anh Biến kỳ tự nguyện hiến tế) + hàng trăm Hóa Thần + vô số Nguyên Anh. 12 hồn phách tử kim là linh hồn phiên — điều khiển chúng = điều khiển toàn bộ hồn phiên. Phân loại: ngụy tiên bảo (dùng cả linh lực lẫn tiên lực), khác linh bảo (chỉ linh lực) và tiên bảo (chỉ tiên lực) @c0388. Thần thông gốc = dung hợp hồn phách; hồn phách Vấn Đỉnh khi xuất hiện là sản phẩm dung hợp — không duy trì lâu nhưng một nén nhang đủ đấu Vấn Đỉnh tu sĩ @c0390. Đệ tứ chủ hồn: uy lực thật sự khiến Vấn Đỉnh Hậu Kỳ kiêng kị; mấy vạn năm chỉ xuất một lần (lần duy nhất: lão tổ Luyện Hồn tông Vấn Đỉnh Sơ Kỳ cùng đệ nhị Chu Tước Tử chống bốn Vấn Đỉnh Hậu Kỳ ngoài tới) @c0390. Truyền thống Luyện Hồn tông dùng Tôn Hồn Phiên cướp tiên ngọc — ác danh lan khắp @c0388. Dùng lần 1: hô Thôn, 12 chủ hồn Anh Biến phun tơ vàng bao lão tổ Cự Ma, hơn triệu hồn phách nuốt ép thành da bọc xương @c0374–@c0375. Dùng lần 2: dung hợp mười chủ hồn Anh Biến xuất hiện, cửu diệp thuật chú sư kinh sợ lui binh @c0390. Tiên Di tộc hứa không vào Luyện Hồn tông nửa bước vì kiêng kị bảo này @c0390.","nguon":["@c0363","@c0369","@c0370","@c0371","@c0374","@c0375","@c0376","@c0377","@c0387","@c0388","@c0389","@c0390"]},{"id":"cu-phu-do-tien-to-cu-ma","name":"Cự phủ đỏ (di vật tổ tiên Cự Ma tộc)","cn":"","aliases":["Khai Thiên phủ"],"category":"than-khi","categoryLabel":"Thần khí — Di vật tổ tiên","phamCap":"Di vật bí truyền tổ tiên Cự Ma tộc — từng chém hai Cửu Diệp thuật chú sư Tiên Di tộc","soHuu":["lao-to-cu-ma","vuong-lam"],"trangThai":"VL thu và nuốt vào Nguyên Thần để tế luyện sau khi giết lão tổ Cự Ma @c0375","blurb":"Chiếc cự phủ phát ánh sáng hồng đỏ, cất trong ngọn núi cao nhất cực Đông tộc Cự Ma. Năm xưa tổ tiên Cự Ma dùng để khai phá trời đất khi di cư tới Chu Tước tinh, chém hai Cửu Diệp thuật chú sư Tiên Di tộc đổi lấy đất định cư. Khi lão tổ cầm tia chớp đỏ lan khắp người, sức mạnh tăng vọt nhưng đốt sinh lực; VL thu sau khi giết lão tổ.","detail":"Cự phủ tổ tiên cất trong ngọn núi cao nhất cực Đông tộc Cự Ma @c0372 — VL cảm giác kỳ lạ khi nhìn núi, foreshadowing bảo vật. Lão tổ triệu ra bằng pháp ấn bí truyền: quỳ bái xưng đệ tử đời thứ 67, hô triệu tổ tiên — núi tách đôi, cự phủ bay lên @c0373. Công năng: khi lão tổ cầm, vòng tuần hoàn khí đỏ bao người, sức mạnh tăng đột biến, thậm chí mọc lại cánh tay bị chặt đứt @c0374. Nhưng đốt sinh lực khiến lão tổ khô quắt rút đi 1/3 @c0374. Đòn tối hậu: hô Tổ tiên che chở, triệu tia chớp hồng mang thiên uy lao xuống @c0374. Bên trong có phủ hồn. VL thu lấy sau khi diệt lão tổ, nuốt vào Nguyên Thần để tế luyện @c0375.","nguon":["@c0373","@c0374","@c0375"]},{"id":"phuong-loan-chi-hon","name":"Phượng Loan chi hồn","cn":"","aliases":["pháp hồn Phượng Loan"],"category":"phap-bao","categoryLabel":"Pháp bảo — Pháp hồn","phamCap":"Pháp hồn cổ xưa — sức mê hoặc đủ lay chuyển tu sĩ Anh Biến","soHuu":["lao-to-cu-ma"],"trangThai":"Lão tổ Cự Ma phong ấn trong pháp bảo — Hứa Lập Quốc xin VL cứu ra @c0373","blurb":"Pháp hồn của nàng Phượng Loan — vẻ đẹp thiên kiều bá mị toát sức mê hoặc mãnh liệt. Lão tổ Cự Ma vô ý tìm được bên trong một pháp bảo; dùng nó khống chế kiếm hồn Hứa Lập Quốc (Hứa gọi nàng là tiểu muội muội tiên tử). Sau khi lão tổ chết Hứa Lập Quốc xin VL giải phong ấn để cứu pháp hồn này.","detail":"Lão tổ Cự Ma vô tình tìm được pháp hồn Phượng Loan bên trong một pháp bảo cổ @c0372. Pháp hồn toát ra vẻ dâm dục thiên kiều bá mị — uy lực mê hoặc cực mạnh, năm xưa suýt mê hoặc cả lão tổ, may pháp hồn bị vỡ nát một phần. Lão tổ dùng nó để lấy lòng và khống chế kiếm hồn Hứa Lập Quốc — Hứa mê mẩn gọi là tiểu muội muội tiên tử @c0372. Sau khi VL giết lão tổ, Hứa Lập Quốc xin VL cứu pháp hồn Phượng Loan ra khỏi phong ấn @c0373.","nguon":["@c0372","@c0373"]},{"id":"phap-luan-phong-an-mi-co","name":"Pháp luân phong ấn Mị Cơ","cn":"","aliases":["pháp luân mười ký hiệu cổ"],"category":"phap-bao","categoryLabel":"Pháp bảo — Phong ấn","phamCap":"Cao cấp (mang mười ký hiệu cổ quái, có thể tự hóa giải linh quang tấn công)","soHuu":[],"trangThai":"Bị Vương Lâm phá vỡ @c0376","blurb":"Pháp luân hơn một tấc vẻ ngoài bình thường có chỗ rỉ sét — ẩn mười ký hiệu cổ quái tự sinh vầng sáng hóa giải linh quang tấn công, dùng để phong ấn hồn phách Mị Cơ. VL phá vỡ bằng cách ấn ký hiệu vào, pháp luân vỡ vụn.","detail":"VL tìm thấy pháp luân trong túi trữ vật lão tổ Cự Ma @c0376. Ngoại hình bình thường, có chỗ rỉ sét nhưng ẩn mười ký hiệu cổ quái — các ký hiệu này sinh ra vầng sáng tự động hóa giải linh quang khi bị tấn công. Chức năng: phong ấn hồn phách Mị Cơ (pháp hồn có ý cảnh mê hoặc vạn vật, kể cả Anh Biến tu sĩ). VL dùng Tỏa Thần thuật miễn nhiễm ý cảnh Mị Cơ, rồi ấn ký hiệu vào pháp luân phá vỡ phong ấn @c0376.","nguon":["@c0376"]},{"id":"bao-thap-tien-ngoc","name":"Bảo tháp tiên ngọc (Tiên Ngọc Bảo Tháp)","cn":"","aliases":["Tiên Ngọc Bảo Tháp","bảo tháp tiên khí"],"category":"phap-bao","categoryLabel":"Pháp bảo — Không gian chứa đựng","phamCap":"Không rõ nguồn gốc — tiên khí phong phú nuôi dưỡng thân người","soHuu":["vuong-lam"],"trangThai":"VL đang giữ — chứa Chu Như, Tiểu Bạch, tiên thi Chu Dật","blurb":"Bảo tháp chứa lượng lớn tiên khí bên trong, có thể nuôi dưỡng thân thể người bên trong (ích cốc). VL dùng cất giữ Chu Như, Tiểu Bạch; gắn thần thức Chu Dật. VL không tiêu thụ tiên lực bên trong vì đã hứa bảo tồn tiên thi.","detail":"VL dùng bảo tháp cất Chu Như và Tiểu Bạch vào trong @c0377. Tiên khí bên trong nuôi dưỡng thân thể người (ích cốc) nên Chu Như không bị ảnh hưởng dù ở lâu. Thần thức Chu Dật gắn vào bảo tháp — lý do VL không tiêu dùng tiên lực bên trong: đã hứa bảo tồn tiên thi của Chu Dật @c0383. Ngoài ra VL còn cất trữ trái cây (từ Nguyệt tinh) trong bảo tháp @c0383. Tiên lực trong bảo tháp là tài nguyên tiên giới cực kỳ trân quý sau khi tiên giới sụp đổ — VL kiềm chế không dùng vào tu luyện vì coi trọng lời hứa với Chu Dật.","nguon":["@c0377","@c0383","@c0387"]},{"id":"toa-anh-qua","name":"Toái Anh Quả","cn":"","aliases":["Quả Toái Anh","trái cây Toái Anh"],"category":"dan-duoc","categoryLabel":"Đan dược — Trái cây linh dược","phamCap":"Linh vật thiên nhiên — khiến Nguyên Anh ăn vào cực kỳ suy yếu (không chết)","soHuu":["vuong-lam"],"trangThai":"Tiểu Bạch tìm được và mang về; Chu Như ăn để làm suy yếu Nguyên Anh Lý Mộ Uyển @c0379","blurb":"Quả mọc trên nhánh cây màu hồng — Tiểu Bạch chịu thương tích lặn lội mang về để Chu Như ăn. Tên do Vương Lâm đặt: Toái Anh — ý là phá/làm tan Nguyên Anh. Ăn vào Nguyên Anh không chết nhưng cực kỳ suy yếu, là phương án làm suy yếu Nguyên Anh Lý Mộ Uyển đang phụ thể trong người Chu Như.","detail":"Tiểu Bạch (linh thú bạch hổ) mất mấy tháng tự tìm và bị thương khi mang trái Toái Anh về cho Chu Như @c0378. VL xướng tên Toái Anh Quả cho trái cây này. Công năng: tu sĩ hoặc thực thể Nguyên Anh ăn vào không chết nhưng bị suy yếu cực kỳ @c0379. Mục tiêu ứng dụng: Chu Như ăn để Nguyên Anh Lý Mộ Uyển phụ thể bên trong bị suy yếu — tạo điều kiện cho VL xử lý vấn đề Lý Mộ Uyển chiếm dần hồn phách đứa bé mà không tổn hại Chu Như @c0379.","nguon":["@c0378","@c0379"]},{"id":"hat-chau-thien-nghich","name":"Hạt châu Thiên Nghịch","cn":"","aliases":["Nghịch Thiên châu","Thiên Nghịch châu"],"category":"phap-bao","categoryLabel":"Pháp bảo — Không gian bản mệnh","phamCap":"Bản mệnh pháp bảo cực phẩm — không gian riêng bên trong mi tâm VL","soHuu":["vuong-lam"],"trangThai":"VL đang sở hữu — thường trực trong mi tâm; đang chứa Nguyên Anh Tư Đồ Nam và Nguyên Anh Lý Mộ Uyển","blurb":"Hạt châu bản mệnh nằm trong mi tâm Vương Lâm, chứa không gian riêng. VL dùng để cứu Nguyên Anh Lý Mộ Uyển khỏi thiên đạo + khỏi tan vỡ bằng cách thu vào bên trong @c0381. Tư Đồ Nam cũng được bảo toàn nhờ Nghịch Thiên châu @c0390. Lý do VL phải giết Cự Ma lão tổ: lão biết VL có Nghịch Thiên châu.","detail":"Hạt châu Thiên Nghịch là bản mệnh pháp bảo nằm sẵn trong mi tâm Vương Lâm. Không gian bên trong linh hoạt — có thể thu nạp và bảo tồn thực thể. Khi sứ giả thiên đạo đến truy Nguyên Anh Lý Mộ Uyển (vừa thoát xác khỏi Chu Như), VL thu Nguyên Anh Lý Mộ Uyển vào Thiên Nghịch châu để cứu thoát @c0381. Không gian bên trong: Nguyên Anh Tư Đồ Nam ở giữa, Nguyên Anh Lý Mộ Uyển ở phía Đông; linh dịch vô số bao phủ và dung nhập Nguyên Anh LMU dưỡng thân @c0382. Tư Đồ Nam khi bị phá thân thể, Nguyên Anh nhập Thiên Nghịch châu mới bảo toàn tính mạng @c0390. Cự Ma lão tổ biết VL có Nghịch Thiên châu — đây là lý do VL bắt buộc phải diệt lão để bịt miệng @c0375.","nguon":["@c0375","@c0381","@c0382","@c0390"]},{"id":"tien-ngoc","name":"Tiên ngọc","cn":"","aliases":["tiên ngọc tiên giới"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu — Tiên lực","phamCap":"Tiên giới (cực hiếm sau đại nạn — tiên mạch tiêu tan, chỉ còn tiên ngọc lưu lại)","soHuu":["vuong-lam"],"trangThai":"VL đang có (thu từ Cự Ma lão tổ, Luyện Hồn tông cấm địa, cướp khắp Bỉ Lô quốc)","blurb":"Vật ngậm tiên lực — chỉ xuất hiện ở tiên giới; sau khi tiên giới sụp đổ cực kỳ hữu hạn. Nhân tố quyết định để Hóa Thần đột phá Anh Biến. Một tia tiên lực ngang toàn bộ linh lực một tu sĩ Kết Đan. Cả bọn tướng cướp tiên ngọc là truyền thống Luyện Hồn tông.","detail":"Tiên ngọc là tài nguyên tu luyện cốt lõi giai đoạn Anh Biến và Vấn Đỉnh @c0383. Một tia tiên lực = toàn bộ linh lực tu sĩ Kết Đan. Sau khi tiên giới sụp đổ, tiên mạch tiêu tan, chỉ còn tiên ngọc lưu lại ở tu chân tinh — cực kỳ trân quý và hữu hạn. Vào Vấn Đỉnh cần gấp vạn lần lượng Anh Biến @c0383. VL thu được từ túi trữ vật Cự Ma lão tổ @c0375, từ cấm địa Luyện Hồn tông (hai khối lớn do Độn Thiên tìm ở tiên giới khi trẻ — VL hút cạn Anh Biến 1/3 @c0388), và từ cướp khắp Bỉ Lô quốc cùng Độn Thiên (tứ cấp tu chân quốc + hơn mười ba tông phái + trăm gia tộc) @c0389. Tiên kiếm VL dùng tiên lực phát kim quang khai thiên tích địa — xác nhận tiên bảo @c0388.","nguon":["@c0375","@c0383","@c0387","@c0388","@c0389"]},{"id":"moc-con-tim-canh-luan-hoi","name":"Mộc côn tím (cành Luân Hồi thụ — Tiên Di tộc)","cn":"","aliases":["cành Luân Hồi tổ thụ"],"category":"phap-bao","categoryLabel":"Pháp bảo — Truyền tống","phamCap":"Cổ vật cấp Luân Hồi thụ — kết nối tổ thụ thực hiện na di toàn tinh cầu","soHuu":[],"trangThai":"Tên Tiên Di tộc Lục diệp dùng để trốn, bị VL chặn không thoát được @c0386","blurb":"Cành màu tím của Luân Hồi tổ thụ, Tiên Di tộc luyện bằng bí pháp để dùng như phương tiện truyền tống na di. Khi kích hoạt kết nối Luân Hồi tổ thụ, thực hiện na di phạm vi lớn trên toàn Chu Tước tinh. Tên Lục diệp dùng để trốn khi gặp VL nhưng thất bại vì VL xé khe nứt không gian chặn đường.","detail":"Mộc côn màu tím là cành của Luân Hồi tổ thụ — cây gốc của Tiên Di tộc, khác với Luân Hồi thụ trong Tiên Di chi địa mà VL đã thu @c0386. Tiên Di tộc luyện bằng bí pháp tộc riêng, kết nối tổ thụ thực hiện na di phạm vi lớn — phủ trên toàn bộ Chu Tước tinh, không giới hạn vị trí @c0386. Tên Lục diệp Thuật Chú Sư dùng để trốn sau khi thua VL tại Hằng Nhạc sơn @c0386. VL xé khe nứt không gian cự đại chặn đường, tên địch không thể na di thoát.","nguon":["@c0386"]},{"id":"ngoc-gian-du-bao-vuong-gia","name":"Ngọc giản dư bảo Vương gia","cn":"","aliases":["ngọc thạch dư bảo Vương gia"],"category":"phap-bao","categoryLabel":"Pháp bảo — Dư bảo gia tộc","phamCap":"Chứa một tia Cực Cảnh VL — đủ giết chắc tu sĩ Nguyên Anh kỳ","soHuu":["vuong-lam"],"trangThai":"Đã kích hoạt — giết hai tên Tiên Di tộc xâm nhập tổ trạch Vương gia @c0385","blurb":"Ngọc giản giấu trong ngăn bí mật sau bài vị tổ tại tổ trạch Vương gia — chứa một tia Cực Cảnh do Vương Lâm lưu lại từ trước. Kích hoạt bằng máu bổn tộc + phù hiệu di huấn gia chủ. Tự động kích nổ khi Tiên Di tộc xâm nhập, bao phủ khí tức hủy diệt giết hai tên.","detail":"VL để lại ngọc giản này cho gia tộc từ trước @c0385. Cất trong ngăn bí mật sau bài vị tổ tại tổ trạch Vương gia. Cơ chế kích hoạt: cắn lưỡi lấy máu vẽ phù hiệu di huấn mà mỗi gia chủ phải ghi nhớ lên ngăn bí mật @c0385. Khi Tiên Di tộc xâm nhập tổ trạch, một tia Cực Cảnh VL bên trong phát uy lực — bao phủ khí tức hủy diệt tự động giết hai tên Tiên Di tộc @c0385. Với tu vi xưa VL để lại, một tia Cực Cảnh đủ giết bất kỳ tu sĩ Nguyên Anh kỳ nào. VL sau đó lấy ngọc giản ra và cho vào một đạo thần thức mới @c0387.","nguon":["@c0385","@c0386","@c0387"]},{"id":"tuong-go-truyen-thua","name":"Tượng gỗ truyền thừa (Thiên Đạo tông)","cn":"","aliases":["tượng gỗ Tuế Nguyệt"],"category":"phap-bao","categoryLabel":"Pháp bảo — Vật truyền thừa","phamCap":"Chứa ý cảnh tu sĩ Hóa Thần kỳ (VL); người vô duyên không mở được","soHuu":["vuong-lam"],"trangThai":"Đặt ở Hằng Nhạc sơn trong Thiên Đạo tông; VL lưu thần thức mới @c0386 rồi ném chìm sâu vào lòng núi","blurb":"Tượng gỗ Tuế Nguyệt đẽo từ đoạn Luân Hồi Mộc — bên trong chứa một tia ý cảnh của Vương Lâm (cấp Hóa Thần kỳ). Ai đạt được trở thành đệ tử trực hệ; thần thức thủ hộ tự động — người vô duyên không mở được. Khi Triệu quốc bị diệt tộc thì phát uy lực; phát quầng sáng phá phù long Tiên Di tộc.","detail":"VL đẽo tượng gỗ Tuế Nguyệt từ đoạn Luân Hồi Mộc @c0330, để lại tại Thiên Đạo tông trên Hằng Nhạc sơn làm vật truyền thừa @c0385. Chứa một tia ý cảnh của VL cấp Hóa Thần — thần thức thủ hộ tự động khiến người vô duyên không mở được; người hữu duyên đạt được thì thành đệ tử trực hệ. Khi Tiên Di tộc tấn công Triệu quốc, tượng gỗ phát quầng sáng phá hơn nửa phù long Lục diệp Thuật Chú Sư @c0385. Tên Lục diệp đoạt tượng gỗ nhưng VL lấy lại, dùng Phù bạo hô kích hoạt tượng nổ tung tấn công địch @c0386. VL sau đó lưu thần thức mới lên tượng gỗ và ném chìm sâu vào lòng Hằng Nhạc sơn để tiếp tục bảo vệ Triệu quốc @c0386.","nguon":["@c0385","@c0386","@c0387"]},{"id":"ngoc-gian-y-canh-lieu-mi","name":"Ngọc giản ý cảnh Liễu Mi","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Vật phẩm — Ý cảnh ngọc giản","phamCap":"Chứa ý cảnh Liễu Mi — Anh Biến kỳ đỉnh phong","soHuu":["vuong-lam"],"trangThai":"Chu Vũ Thái dùng sinh tử đổi lấy từ Liễu Mi, trao cho VL @c0387","blurb":"Ngọc giản chứa ý cảnh của Liễu Mi (nhân vật tiên thiên kỳ tài Chu Tước tinh, cấp Anh Biến). Chu Vũ Thái dùng sinh tử trả giá cảm ngộ ý cảnh này từ Liễu Mi, rồi đưa cho VL để VL cắn nuốt đạo tâm thành tựu Chu Tước chi thế.","detail":"Chu Vũ Thái — một trong bốn người được Vân Tước tuyển chọn — dùng sinh tử (mạng sống) làm đối giá cảm ngộ ý cảnh của Liễu Mi, lưu vào ngọc giản đưa cho VL @c0387. VL cắn nuốt đạo tâm Liễu Mi từ ngọc giản để thành tựu Chu Tước chi thế — một loại ý cảnh/đạo tâm đặc biệt của Chu Tước tinh. Chi tiết công năng và quá trình thành tựu chưa được triển khai thêm trong chương này.","nguon":["@c0387"]},{"id":"kiem-cu-phu","name":"Kiếm Cự Phú","cn":"","aliases":["phi kiếm Cự Phú"],"category":"phap-bao","categoryLabel":"Pháp bảo — Kiếm cổ","phamCap":"Bất minh — Hằng Nhạc phái từng gặp đại kiếp nạn diệt môn, Cự Phú giải được","soHuu":["vuong-lam"],"trangThai":"VL tìm được trong di tích động phủ Hằng Nhạc phái @c0387","blurb":"Phi kiếm cổ trong di tích động phủ Hằng Nhạc phái — chiếc nôi đưa VL vào tu tiên kiếp này. Bên trong kiếm có một đạo kiếm quyết do vị tiền bối Hằng Nhạc để lại cho đệ tử hữu duyên. Hằng Nhạc phái năm xưa gặp đại kiếp nạn diệt môn nhưng Cự Phú giải được.","detail":"VL tìm thấy kiếm Cự Phú trong động phủ hoang phế đầy tro bụi của Hằng Nhạc phái xưa trên Tượng Xà sơn @c0387. Trong động có hài cốt và ngọc giản của vị tiền bối đúc kiếm. Bên trong kiếm Cự Phú lưu một đạo kiếm quyết — Kiếm quyết Cự Phú — dành cho đệ tử hữu duyên đời sau @c0387. Lịch sử: Hằng Nhạc phái từng gặp đại kiếp nạn diệt môn nhưng nhờ kiếm Cự Phú mà giải được @c0387. Sau đó VL còn gặp lại kiếm Cự Phú trong bối cảnh Luyện Hồn tông — thuật chú Đỉnh/cửu diệp thuật chú sư Tiên Di tộc trong một trận giao tranh @c0389.","nguon":["@c0387","@c0389"]},{"id":"binh-ngoc-do-mau-co-than","name":"Bình ngọc đỏ đựng máu Cổ Thần","cn":"","aliases":["bình máu Cổ Thần"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu — Huyết dịch cổ tộc","phamCap":"Máu chứa chút khí tức bộ tộc Cổ Thần — thi triển thần thông Cổ Thần hoặc hấp thu để tăng cường","soHuu":["vuong-lam"],"trangThai":"VL thu từ túi trữ vật Cự Ma lão tổ @c0375","blurb":"Bình ngọc màu đỏ chứa chất lỏng đỏ như máu thật — ẩn chứa chút máu của bộ tộc Cổ Thần. Người dùng có thể thi triển thần thông tộc Cổ Thần, hoặc cho VL hấp thu để tăng cường thân thể Cổ Thần của mình. VL thu từ túi trữ vật lão tổ Cự Ma sau khi giết lão.","detail":"Lão tổ Cự Ma trong túi trữ vật có bình ngọc đỏ chứa máu Cổ Thần @c0375. Bình ngọc màu đỏ, chất lỏng bên trong đỏ như máu thật. Công năng: chứa chút khí tức bộ tộc Cổ Thần, có thể dùng để thi triển thuật thần thông của tộc Cổ Thần, hoặc cho Vương Lâm (đã thành thân thể Cổ Thần) hấp thu để tăng cường. VL thu lấy cùng với cự phủ đỏ và tiên ngọc từ túi trữ vật lão tổ sau khi diệt lão @c0375. Tương tự vật VL từng gặp ở Triệu quốc (Đằng gia) — tộc nhân có vật chứa máu Cổ Thần tương tự @c0375.","nguon":["@c0375"]},{"id":"tinh-la-ban-vuong-lam","name":"Tinh La Bàn (của Vương Lâm)","cn":"","aliases":["La bàn tinh không VL"],"category":"phap-bao","categoryLabel":"Pháp bảo — Di chuyển tinh không","phamCap":"Tốc độ cực nhanh như tia chớp trong tinh không; nửa tháng từ Nguyệt tinh tới Chu Tước tinh","soHuu":["vuong-lam"],"trangThai":"VL đang dùng để di chuyển giữa các tinh cầu","blurb":"Pháp bảo Tinh La Bàn riêng của Vương Lâm — dùng để di chuyển trong tinh không giữa các tinh cầu với tốc độ cực nhanh như tia chớp. Nửa tháng đi từ Nguyệt tinh tới Chu Tước tinh. Khác với Tinh La Bàn ngụy của Sất Hổ (bản sao của Cự Ma tộc, đã bị hỏng).","detail":"VL dùng Tinh La Bàn riêng của mình để bay giữa các tinh cầu trong tinh không @c0375. Tốc độ cực nhanh, nhanh như tia chớp @c0383. Nửa tháng đủ đi từ Nguyệt tinh tới Chu Tước tinh @c0383. Điều kiện sử dụng: cần đạt Anh Biến kỳ mới di chuyển được trong tinh không @c0378. Bảo vật này khác hoàn toàn với Tinh La Bàn ngụy (bản sao) của Sất Hổ — Sất Hổ chỉ có bản sao chí bảo Cự Ma tộc, đã bị hỏng sau trận hư vô @c0287; La bàn của VL là vật riêng, hoạt động bình thường.","nguon":["@c0375","@c0378","@c0383"]},{"id":"thap-van-hon-phien-vl","name":"Thập vạn hồn phiên (VL tự luyện)","cn":"","aliases":["hồn phiên chủ hồn Lý Nguyên Phong"],"category":"phap-bao","categoryLabel":"Pháp bảo — Hồn Phiên","phamCap":"Thập vạn cấp — chủ hồn là hồn phách Lý Nguyên Phong (Anh Biến kỳ, thần trí xóa)","soHuu":["vuong-lam"],"trangThai":"VL đã luyện và đang dùng @c0373","blurb":"Hồn Phiên do Vương Lâm tự luyện — chủ hồn là hồn phách Lý Nguyên Phong (Anh Biến kỳ, đã bị xóa thần trí), nên uy lực rất mạnh. Chứa mấy ngàn hồn phách. VL hô Diệt → hồn phách ào ào lao diệt Hắc Viêm thú của lão tổ Cự Ma.","detail":"VL tự luyện hồn phiên với chủ hồn là hồn phách Lý Nguyên Phong — Anh Biến kỳ tu sĩ, bị xóa thần trí trước khi dùng làm chủ hồn @c0373. Vì chủ hồn là Anh Biến kỳ nên uy lực hồn phiên này rất mạnh, dù cấp chỉ là Thập vạn (chứa mấy ngàn hồn phách). Dùng trong trận chiến với lão tổ Cự Ma: VL hô Diệt, hồn phách lao ào ào tấn công Hắc Viêm thú do lão tổ triệu bằng mộc côn đen @c0373. Đây là hồn phiên VL tự chế riêng, khác với Thập Ức Tôn Hồn Phiên nhận từ Độn Thiên.","nguon":["@c0373"]},{"id":"xac-rua","name":"Xác rùa","cn":"","aliases":[],"category":"","categoryLabel":"","phamCap":"","soHuu":[],"uuTien":80,"trangThai":"","blurb":"Pháp bảo phòng ngự của lão bà Trĩ Ma Đạo, chặn kiếm quang tiên bảo Vương Lâm bất thành.","detail":"","nguon":["@c0388"]},{"id":"thien-ton-dan","name":"Thiên Tổn đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Ngũ phẩm sơ khai","soHuu":"Vân Thiên tông (Sở quốc)","blurb":"Đan dược trứ danh do Vân Thiên tông luyện chế, đạt ngũ phẩm sơ khai. Công hiệu đặc biệt với Nguyên Anh đã mất thân thể: lập tức chữa trị/tái sinh thân thể cũ mà không cần đoạt xá. Chính nhờ đan này Vân Thiên tông càng nổi danh; tu chân quốc cấp bốn Cự Ma tộc phải dùng hiệp nghị bí mật hạng nhất mới đổi được.","detail":"Thiên Tổn đan giúp Nguyên Anh mất thân thể tái sinh thân cũ không cần đoạt xá — vật phẩm cực giá trị @c0188. Năm 134.500 Vân Thiên tông ra Thiên Tổn đan ngũ phẩm → danh tiếng lên đỉnh, Cự Ma tộc đổi đan bằng hiệp nghị bí mật hạng nhất + cài pháp trận trước cửa tông. Đây là một lý do Vương Lâm nhắm Vân Thiên tông (tông luyện đan) để có đan dược cho phân thân @c0188.","nguon":["@c0188"]},{"id":"that-long-dinh","name":"Thất Long đỉnh","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo — đan đỉnh","phamCap":"Hiệu quả không kém Đoạt Thiên Thất đỉnh nhiều","soHuu":"Lý Mộ Uyển","blurb":"Đan đỉnh do Lý Mộ Uyển lén luyện chế trong mấy năm ở Vân Thiên tông sau khi tìm hiểu Đoạt Thiên Thất đỉnh. Trên đỉnh có bảy con hắc long phun sương mù đen; vốn định làm đòn sát thủ tối hậu để phá Đoạt Thiên Thất đỉnh, sau đổi công năng dẫn linh lực ngàn năm xuống cho bổn tôn Vương Lâm tu luyện.","detail":"Thất Long đỉnh hiệu quả không kém Đoạt Thiên Thất đỉnh; bảy hắc long khi kích hoạt bay lên hóa hư ảnh đan đỉnh, sáu vây một @c0199. Lý Mộ Uyển dùng nó đồng bộ với Đoạt Thiên Thất đỉnh để trộm linh lực + giải phong ấn đan lô, đồng thời chứa bổn tôn Vương Lâm tu luyện hấp thu linh lực ngàn năm @c0199–@c0200.","nguon":["@c0199","@c0200"]},{"id":"luc-dao-linh-dan","name":"Lục Đạo linh đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Khoảng ngũ phẩm (mốc để Âu Dương Tử thử lục phẩm)","soHuu":"Âu Dương Tử (Vân Thiên tông)","blurb":"Đan dược mới Âu Dương Tử luyện thành nhờ sáu du hồn luyện đan sư tương trợ; màu vàng, nổi lên từ đan đỉnh kèm dị tượng (trời tối hóa sáng). Là cột mốc giúp Âu Dương Tử tiến tới thử luyện lục phẩm linh đan.","detail":"Âu Dương Tử luyện thành Lục Đạo linh đan trên quảng trường Vân Thiên tông (làm bình phong cho Song tu điển lễ), nhờ sáu du hồn luyện đan sư; sau khi đan thành các du hồn lưu luyến rồi tiêu tán, được Âu Dương Tử tế bái. Thành công này khiến hắn tự tin có thể thử luyện lục phẩm linh đan @c0200.","nguon":["@c0200"]},{"id":"tu-tinh-thach","name":"Tử Tinh thạch","cn":"","aliases":[],"category":"vat-pham","categoryLabel":"Tài liệu luyện khí","phamCap":"Một viên cỡ nắm tay ≥ 100 khối trung phẩm linh thạch","soHuu":"Thiếu niên (vật gia truyền) → tranh chấp","blurb":"Viên ngọc màu tím to chừng nắm tay, sáng long lanh trong suốt; thực ra không phải ngọc mà là một loại tài liệu luyện khí giá trị cao. Là vật tranh chấp giữa thiếu niên và người đàn ông trung niên tại Liên Mặc Thành.","detail":"Tử Tinh thạch là tài liệu luyện khí, một viên lớn cỡ nắm tay bán được ít nhất trên 100 khối trung phẩm linh thạch @c0206. Người đàn ông trung niên cướp viên Tử Tinh thạch (vật gia truyền) của thiếu niên; sau khi Vương Lâm giết kẻ cướp, thiếu niên nhặt lại viên ngọc rồi chạy @c0206.","nguon":["@c0206"]},{"id":"yeu-huyet-dan","name":"Yêu Huyết đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Tứ phẩm","soHuu":"Âu Dương Tử (dùng làm chủ tế)","blurb":"Viên đan tứ phẩm đỏ như máu, tỏa mùi tanh huyết, đựng trong bạch ngọc bình niêm sáp. Âu Dương Tử dùng làm chủ tế trong Tế đan luyện thuật — ném vào một đan đỉnh tạo cột sáng đỏ như máu (thông thiên huyết trụ).","detail":"Yêu Huyết đan là viên tứ phẩm đỏ như máu; luyện đan sư cầm nó run rẩy, mặt tái nhợt, cắn răng ném vào một trong sáu đan đỉnh → bốc cột sáng đỏ như máu @c0199. Đóng vai chủ tế trong nghi thức Tế đan luyện ngũ phẩm linh đan của Âu Dương Tử.","nguon":["@c0199"]},{"id":"la-lam-dan","name":"La Lâm đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Tứ phẩm","soHuu":"Âu Dương Tử (dùng làm thứ tế)","blurb":"Viên đan tứ phẩm màu xanh lam, Âu Dương Tử dùng làm thứ tế trong Tế đan luyện thuật — đặt vào vòng đan đỉnh tạo cột sáng màu lam.","detail":"La Lâm đan là viên tứ phẩm màu xanh lam, đóng vai thứ tế trong nghi thức Tế đan luyện ngũ phẩm linh đan; đặt vào vòng đan đỉnh tạo cột sáng màu lam (một trong sáu cột sáng đủ màu) @c0199.","nguon":["@c0199"]}]};
